## Task Description

Add a comprehensive `/status` API endpoint to the daemon that returns complete system state including daemon info, worker status, circuit states, and recent build history.

## Design

### Response Structure
```rust
// In rchd/src/api.rs or rch-common/src/protocol.rs

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StatusResponse {
    /// Daemon information
    pub daemon: DaemonInfo,
    /// All workers with their status
    pub workers: Vec<WorkerInfo>,
    /// Recent build history
    pub recent_builds: Vec<BuildRecord>,
    /// Current issues/warnings
    pub issues: Vec<Issue>,
    /// Summary statistics
    pub stats: StatusStats,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DaemonInfo {
    /// Process ID
    pub pid: u32,
    /// Daemon version
    pub version: String,
    /// Uptime in seconds
    pub uptime_secs: u64,
    /// Socket path
    pub socket_path: String,
    /// Config file path
    pub config_path: Option<String>,
    /// When daemon started
    pub started_at: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkerInfo {
    /// Worker ID
    pub id: String,
    /// Hostname
    pub host: String,
    /// SSH user
    pub user: String,
    /// Worker health status
    pub status: WorkerStatus,
    /// Circuit breaker state (after circuit breaker epic)
    pub circuit: Option<CircuitStateInfo>,
    /// Used slots
    pub used_slots: u32,
    /// Total slots
    pub total_slots: u32,
    /// Speed score (0-100)
    pub speed_score: f64,
    /// When last health check occurred
    pub last_health_check: Option<DateTime<Utc>>,
    /// Last health check latency in ms
    pub last_check_latency_ms: Option<u64>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Issue {
    /// Severity level
    pub level: IssueLevel,
    /// Short description
    pub message: String,
    /// Related worker (if any)
    pub worker_id: Option<String>,
    /// Suggested action
    pub suggestion: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum IssueLevel {
    Warning,
    Error,
    Info,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StatusStats {
    /// Total workers configured
    pub total_workers: usize,
    /// Healthy workers
    pub healthy_workers: usize,
    /// Degraded workers
    pub degraded_workers: usize,
    /// Unreachable workers
    pub unreachable_workers: usize,
    /// Total available slots
    pub available_slots: u32,
    /// Total used slots
