### API Implementation
```rust
// In rchd/src/api.rs

impl ApiHandler {
    async fn handle_request(&self, request: &str) -> Response {
        if request.starts_with("GET /status") {
            self.handle_status().await
        } else if request.starts_with("GET /select-worker") {
            // ... existing handler
        } else {
            // ...
        }
    }

    async fn handle_status(&self) -> Response {
        let daemon_info = DaemonInfo {
            pid: std::process::id(),
            version: env!("CARGO_PKG_VERSION").to_string(),
            uptime_secs: self.start_time.elapsed().as_secs(),
            socket_path: self.socket_path.to_string_lossy().to_string(),
            config_path: self.config_path.clone(),
            started_at: self.started_at,
        };

        let workers = self.collect_worker_info().await;
        let recent_builds = self.history.recent(10);
        let issues = self.detect_issues(&workers).await;
        let stats = self.calculate_stats(&workers).await;

        let response = StatusResponse {
            daemon: daemon_info,
            workers,
            recent_builds,
            issues,
            stats,
        };

        Response::json(200, &response)
    }

    async fn collect_worker_info(&self) -> Vec<WorkerInfo> {
        let workers = self.pool.all_workers().await;
        let mut infos = Vec::new();

        for worker in workers {
            let status = worker.status().await;
            let circuit = self.health_monitor.get_circuit_state(&worker.config.id).await;
            let last_check = self.health_monitor.get_last_check(&worker.config.id).await;

            infos.push(WorkerInfo {
                id: worker.config.id.to_string(),
                host: worker.config.host.clone(),
                user: worker.config.user.clone(),
                status,
                circuit: circuit.map(|c| c.into()),
                used_slots: worker.used_slots(),
                total_slots: worker.config.total_slots,
                speed_score: worker.speed_score,
                last_health_check: last_check.map(|r| r.checked_at),
                last_check_latency_ms: last_check.map(|r| r.response_time_ms),
            });
        }

        infos
    }

    async fn detect_issues(&self, workers: &[WorkerInfo]) -> Vec<Issue> {
        let mut issues = Vec::new();

        for worker in workers {
            match worker.status {
                WorkerStatus::Unreachable => {
                    issues.push(Issue {
                        level: IssueLevel::Error,
                        message: format!("Worker '{}' is unreachable", worker.id),
                        worker_id: Some(worker.id.clone()),
                        suggestion: Some("Check network connectivity and SSH access".to_string()),
                    });
                }
                WorkerStatus::Degraded => {
                    issues.push(Issue {
                        level: IssueLevel::Warning,
                        message: format!("Worker '{}' is degraded (slow responses)", worker.id),
                        worker_id: Some(worker.id.clone()),
                        suggestion: Some(format!(
                            "Run 'rch workers probe {}' to diagnose",
                            worker.id
                        )),
                    });
                }
                _ => {}
            }

            // Check for open circuits
            if let Some(ref circuit) = worker.circuit {
                if circuit.state == "open" {
                    issues.push(Issue {
                        level: IssueLevel::Warning,
                        message: format!("Worker '{}' circuit breaker is open", worker.id),
                        worker_id: Some(worker.id.clone()),
                        suggestion: Some(format!(
                            "Circuit will probe in {}s",
                            circuit.next_probe_in_secs.unwrap_or(0)
                        )),
                    });
                }
            }
        }

        // Check for no healthy workers
        if workers.iter().all(|w| !matches!(w.status, WorkerStatus::Healthy)) {
            issues.push(Issue {
                level: IssueLevel::Error,
                message: "No healthy workers available".to_string(),
                worker_id: None,
                suggestion: Some("Builds will fall back to local execution".to_string()),
            });
        }

        issues
    }
}
```

